const msg = $input.first().json;
const update = msg;
let chatId, userId, text, firstName, isCallback, callbackData, messageId;

if (update.callback_query) {
  isCallback = true;
  chatId = update.callback_query.message.chat.id;
  userId = update.callback_query.from.id;
  firstName = update.callback_query.from.first_name;
  callbackData = update.callback_query.data;
  messageId = update.callback_query.message.message_id;
  text = callbackData;
} else if (update.message) {
  isCallback = false;
  chatId = update.message.chat.id;
  userId = update.message.from.id;
  firstName = update.message.from.first_name;
  text = update.message.text || '';
  messageId = update.message.message_id;
  callbackData = null;
} else {
  return [];
}

return [{ json: {
  chatId: String(chatId),
  userId: String(userId),
  firstName,
  text: text.trim(),
  isCallback,
  callbackData,
  messageId,
  raw: update
}}];

const topics = $input.all();
const chatId = $('Parse Telegram Update').first().json.chatId;

if (!topics || topics.length === 0 || !topics[0].json.id) {
  return [{ json: {
    chatId,
    text: '📭 Non hai ancora nessun argomento.\n\nUsa /newtopic per crearne uno!',
    replyMarkup: null
  }}];
}

let msg = '📋 *I tuoi argomenti attivi:*\n\n';
const buttons = [];

topics.forEach((t, i) => {
  const topic = t.json;
  const schedule = topic.schedule === 'none' ? 'Solo on-demand' :
    topic.schedule === 'daily' ? `Giornaliero alle ${topic.schedule_time}` :
    `Settimanale (${topic.schedule_day}) alle ${topic.schedule_time}`;
  const delivery = topic.delivery === 'both' ? 'Telegram + Email' : topic.delivery;
  msg += `*${i+1}. ${topic.name}*\n`;
  msg += `   🔑 ${topic.keywords}\n`;
  msg += `   ⏰ ${schedule} · 📨 ${delivery}\n\n`;
  buttons.push([{ text: `📰 Digest "${topic.name}"`, callback_data: `digest:${topic.id}` }]);
});

msg += '_Clicca su un argomento per un digest immediato._';

return [{ json: {
  chatId,
  text: msg,
  replyMarkup: JSON.stringify({ inline_keyboard: buttons })
}}];

const topics = $input.all();
const chatId = $('Parse Telegram Update').first().json.chatId;

if (!topics || topics.length === 0 || !topics[0].json.id) {
  return [{ json: {
    chatId,
    text: '📭 Nessun argomento trovato. Crea prima un topic con /newtopic',
    buttons: null
  }}];
}

const buttons = topics.map(t => ([{
  text: t.json.name,
  callback_data: `digest:${t.json.id}`
}]));

return [{ json: {
  chatId,
  text: '📰 Su quale argomento vuoi un digest immediato?',
  buttons: JSON.stringify({ inline_keyboard: buttons })
}}];

const data = $input.first().json;
const isCallback = data.isCallback;
const callbackData = data.callbackData || '';
const chatId = data.chatId;

if (isCallback && callbackData.startsWith('digest:')) {
  const topicId = callbackData.split(':')[1];
  return [{ json: { ...data, action: 'digest', value: topicId } }];
}

if (isCallback && callbackData.startsWith('confirm_unsubscribe:')) {
  return [{ json: { ...data, action: 'confirm_unsubscribe', value: 'all' } }];
}

if (isCallback && callbackData.startsWith('cancel:')) {
  return [{ json: { ...data, action: 'cancel', value: callbackData.split(':')[1] } }];
}

// Testo libero: potrebbe essere la risposta al form /newtopic
if (!isCallback && data.text && data.text.includes('NOME:') && data.text.includes('KEYWORDS:')) {
  return [{ json: { ...data, action: 'submit_topic_form', value: data.text } }];
}

return [{ json: { ...data, action: 'unknown', value: data.text } }];

const topic = $input.first().json;
const keywords = (topic.keywords || '').toLowerCase();
const name = (topic.name || '').toLowerCase();

const AI_KEYWORDS = ['ai','artificial intelligence','intelligenza artificiale',
  'llm','machine learning','deep learning','neural','gpt','claude',
  'gemini','openai','anthropic','huggingface','diffusion','transformer'];

const isAI = AI_KEYWORDS.some(k => keywords.includes(k) || name.includes(k));

const AI_FEEDS = [
  { url: 'https://huggingface.co/blog/feed.xml',                              name: 'HuggingFace Blog' },
  { url: 'https://openai.com/blog/rss.xml',                                   name: 'OpenAI Blog' },
  { url: 'https://www.deeplearning.ai/the-batch/feed/',                       name: 'The Batch' },
  { url: 'https://www.anthropic.com/rss.xml',                                 name: 'Anthropic News' },
  { url: 'https://github-trending-rss.vercel.app/repositories?language=python', name: 'GitHub Trending Python' },
  { url: 'https://github-trending-rss.vercel.app/repositories',               name: 'GitHub Trending' },
  { url: 'https://www.technologyreview.com/feed/',                             name: 'MIT Tech Review' },
  { url: 'https://feeds.arstechnica.com/arstechnica/technology-lab',           name: 'Ars Technica AI' }
];

const GENERIC_FEEDS = [
  { url: 'https://feeds.arstechnica.com/arstechnica/technology-lab', name: 'Ars Technica Tech' },
  { url: 'https://feeds.feedburner.com/oreilly/radar',               name: "O'Reilly Radar" },
  { url: 'https://rss.nytimes.com/services/xml/rss/nyt/Technology.xml', name: 'NYT Technology' }
];

const customFeedsRaw = topic.custom_feeds || '';
const customFeeds = customFeedsRaw
  ? customFeedsRaw.split('|||').filter(u => u.trim()).map(url => ({ url: url.trim(), name: 'Custom Feed' }))
  : [];

const feedsToUse = isAI
  ? [...AI_FEEDS, ...customFeeds]
  : [...GENERIC_FEEDS, ...customFeeds];

return [{ json: {
  ...topic,
  isAI,
  feedsToUse,
  searchQuery: topic.keywords
}}];

const items = $input.all();
const MAX_ARTICLES = 20;
const DAYS_BACK = 7;
const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - DAYS_BACK);

const articles = [];
items.forEach(item => {
  if (!item.json.title) return;
  const pub = new Date(item.json.pubDate || item.json.isoDate || item.json.date || Date.now());
  if (pub >= cutoff || !item.json.pubDate) {
    articles.push({
      title:   item.json.title || 'Senza titolo',
      link:    item.json.link  || item.json.url || '',
      summary: (item.json.contentSnippet || item.json.summary || item.json.content || '').substring(0, 400),
      date:    item.json.pubDate || item.json.isoDate || 'N/D',
      source:  item.json.feedTitle || 'RSS'
    });
  }
});

// Deduplication per URL
const seen = new Set();
const unique = articles.filter(a => {
  if (!a.link || seen.has(a.link)) return false;
  seen.add(a.link);
  return true;
});

unique.sort((a, b) => new Date(b.date) - new Date(a.date));
const selected = unique.slice(0, MAX_ARTICLES);

const topicCtx = $('Prepare Sources').first().json;

return [{ json: {
  articles:    selected,
  topicName:   topicCtx.name,
  keywords:    topicCtx.keywords,
  chatId:      topicCtx.chat_id,
  email:       topicCtx.email,
  delivery:    topicCtx.delivery,
  topicId:     topicCtx.id,
  userId:      topicCtx.user_id,
  articleCount: selected.length
}}];

const data = $input.first().json;
const articles = data.articles;

if (!articles || articles.length === 0) {
  return [{ json: {
    ...data,
    skipLLM: true,
    digestText: `📭 *Nessuna notizia recente trovata per "${data.topicName}".*\n\nProva ad espandere le keywords o aggiungi feed RSS con /addfeed.`
  }}];
}

const articlesText = articles.map((a, i) =>
  `${i+1}. **${a.title}** (${a.source}, ${a.date})\n   URL: ${a.link}\n   ${a.summary}`
).join('\n\n');

const prompt = `Sei un giornalista specializzato che produce newsletter di qualità.
L'utente segue l'argomento: "${data.topicName}" con keywords: ${data.keywords}.

Hai a disposizione questi articoli recenti da fonti autorevoli:

${articlesText}

Genera un digest in italiano, stile newsletter professionale:

🗞️ **DIGEST: ${data.topicName}**
📅 ${new Date().toLocaleDateString('it-IT')}

## Panoramica
[2-3 frasi che sintetizzano il momento attuale dell'argomento]

## Notizie Principali
[Per ogni notizia rilevante (max 5): titolo linkato, 2-3 righe di analisi, impatto]

## Da Tenere d'Occhio
[1-2 trend emergenti o sviluppi interessanti]

## Risorse
[Lista link più importanti con titolo breve]

Tono: informativo, preciso, coinvolgente. Solo notizie pertinenti alle keywords. Usa Markdown con grassetti ed emoji per leggibilità su Telegram.`;

return [{ json: { ...data, skipLLM: false, llmPrompt: prompt } }];

const llmOut = $input.first().json;
const src    = $('Build LLM Prompt').first().json;

const digestText =
  llmOut.text ||
  llmOut.message ||
  llmOut.content ||
  (llmOut.choices?.[0]?.message?.content) ||
  'Errore nella generazione del digest.';

return [{ json: { ...src, digestText: digestText.trim() } }];

const data  = $input.first().json;
const text  = data.digestText;
const LIMIT = 4000;

if (text.length <= LIMIT) {
  return [{ json: { ...data, chunk: text } }];
}

const chunks = [];
let i = 0;
while (i < text.length) {
  let end = i + LIMIT;
  if (end < text.length) {
    const nl = text.lastIndexOf('\n', end);
    if (nl > i) end = nl;
  }
  chunks.push(text.substring(i, end));
  i = end;
}

return chunks.map(chunk => ({ json: { ...data, chunk } }));

const data = $input.first().json;
const text = data.text || '';
const chatId = data.chatId;
const userId = data.userId;

const extract = (field) => {
  const regex = new RegExp(`${field}:\\s*(.+)`, 'i');
  const match = text.match(regex);
  return match ? match[1].trim() : null;
};

const nome     = extract('NOME');
const keywords = extract('KEYWORDS');
const schedule = (extract('SCHEDULE') || 'none').toLowerCase();
const ora      = extract('ORA') || '08:00';
const giorno   = (extract('GIORNO') || 'lunedi').toLowerCase();
const delivery = (extract('DELIVERY') || 'telegram').toLowerCase();
const email    = extract('EMAIL');

if (!nome || !keywords) {
  return [{ json: {
    chatId, error: true,
    message: '❌ Formato non valido. Includi almeno NOME e KEYWORDS. Riprova con /newtopic'
  }}];
}

return [{ json: { chatId, userId, nome, keywords, schedule, ora, giorno, delivery, email, error: false } }];
